@dataclass(frozen=True)
class Page:
    title: str
    focus: str
    signals: tuple[str, ...]
    judgement: tuple[str, ...]
    steps: tuple[str, ...]
    exceptions: tuple[str, ...]
    stops: tuple[str, ...]
    records: tuple[str, ...]


def parts(value: str) -> tuple[str, ...]:
    return tuple(part.strip() for part in value.split(";") if part.strip())


def p(title: str, focus: str, signals: str, judgement: str, steps: str, exceptions: str, stops: str, records: str) -> Page:
    return Page(title, focus, parts(signals), parts(judgement), parts(steps), parts(exceptions), parts(stops), parts(records))


