def load_json(path: Path, default):
    if not path.exists():
        return default
    return json.loads(path.read_text(encoding="utf-8"))


def clean(value: str | None) -> str:
    return re.sub(r"\s+", " ", value or "").strip()


def person_info(person: str) -> dict:
    return load_json(PEOPLE_DIR / f"{person}_person_info.json", {})


def authored_count(person: str, summary: dict) -> int:
    path = ROOT / summary.get("all_evidence_path", "")
    rows = load_json(path, [])
    return sum(1 for row in rows if person in (row.get("who") or ""))


def top_sources(summary: dict, limit: int = 10) -> str:
    sources = summary.get("top_sources") or {}
    items = list(sources.items())[:limit] if isinstance(sources, dict) else sources[:limit]
    return ", ".join(f"{name} {count}건" for name, count in items)


def md_list(items: tuple[str, ...]) -> str:
    return "\n".join(f"- {item}" for item in items)


def md_steps(items: tuple[str, ...]) -> str:
    return "\n".join(f"{idx}. {item}" for idx, item in enumerate(items, 1))


def page_to_markdown(idx: int, page: Page) -> str:
    return "\n".join(
        [
            f"## {idx:02d}. {page.title}",
            "",
            page.focus,
            "",
            "### 데이터에서 보인 신호",
            md_list(page.signals),
            "",
            "### 인수인계 판단",
            md_list(page.judgement),
            "",
            "### 처리 절차",
            md_steps(page.steps),
            "",
            "### 특이사항과 예외",
            md_list(page.exceptions),
            "",
            "### 멈춤 조건",
            md_list(page.stops),
            "",
            "### 기록해야 할 항목",
            md_list(page.records),
            "",
            "### 인수자가 기억할 문장",
            f"이 장의 핵심은 `{page.title}` 상황을 단순 처리 이력으로 보지 않고, 위의 멈춤 조건이 해소될 때까지 다음 단계로 넘기지 않는 것이다. 처리자는 근거가 확인된 값과 아직 추정인 값을 분리해서 남겨야 한다.",
            "",
        ]
    )


def build_markdown(person: str, summary: dict) -> str:
    info = person_info(person)
    date_range = summary.get("date_range") or ["", ""]
    direct = authored_count(person, summary)
    header = [
        f"# {person} 업무규칙 인수인계서 30페이지판",
        "",
        "## 문서 작성 기준",
        f"- 작성일: {RUN_DATE}",
        "- 사용 데이터: Teams full-history scrape, person_evidence JSON, data/teams/peoples 업무규칙/업무이력 문서",
        "- 제한: 수집된 정보에서 반복적으로 확인되는 업무 패턴만 사용했고, 개발/AX 요청 자체는 통상업무 규칙에서 제외했다.",
        f"- 부서/직책: {info.get('dept') or ''} / {info.get('position') or ''}",
        f"- ERP main_work: {info.get('main_work') or ''}",
        f"- 근거 메시지: {summary.get('evidence_count')}건, 직접 발화 {direct}건, 통상업무 후보 {summary.get('routine_non_dev_count')}건",
        f"- 기간: {date_range[0]} ~ {date_range[1]}",
        f"- 주요 출처: {top_sources(summary)}",
        "",
        "이 문서는 메시지를 시간순으로 나열하지 않는다. 인수자가 실제로 업무를 넘겨받아 판단할 수 있도록 국가별, 거래처별, 제품별, 오류/예외별 특이사항을 업무규칙으로 재구성했다.",
        "",
        "<!-- PAGEBREAK -->",
        "",
    ]
    body = []
    for idx, page in enumerate(PAGES[person], 1):
        body.append(page_to_markdown(idx, page))
        if idx != len(PAGES[person]):
            body.append("<!-- PAGEBREAK -->\n")
    return "\n".join(header + body)


def set_font(run, size: float = 9.0) -> None:
    run.font.name = "Malgun Gothic"
    run.font.size = Pt(size)
    rpr = run._element.rPr
    rfonts = rpr.rFonts
    if rfonts is None:
        rfonts = OxmlElement("w:rFonts")
        rpr.append(rfonts)
    rfonts.set(qn("w:eastAsia"), "Malgun Gothic")


def add_para(doc: Document, text: str, style: str | None = None, size: float = 9.0) -> None:
    para = doc.add_paragraph(style=style)
    run = para.add_run(text)
    set_font(run, size=size)


def add_table(doc: Document, rows: list[list[str]]) -> None:
    if not rows:
        return
    width = max(len(r) for r in rows)
    table = doc.add_table(rows=1, cols=width)
    table.style = "Table Grid"
    for idx, value in enumerate(rows[0]):
        table.rows[0].cells[idx].text = value
    for row in rows[1:]:
        cells = table.add_row().cells
        for idx in range(width):
            cells[idx].text = row[idx] if idx < len(row) else ""


def markdown_to_docx(markdown: str, path: Path) -> None:
    doc = Document()
    for section in doc.sections:
        section.top_margin = Inches(0.45)
        section.bottom_margin = Inches(0.45)
        section.left_margin = Inches(0.55)
        section.right_margin = Inches(0.55)
    doc.styles["Normal"].font.name = "Malgun Gothic"
    doc.styles["Normal"].font.size = Pt(9)

    lines = markdown.splitlines()
    idx = 0
    while idx < len(lines):
        line = lines[idx].rstrip()
        if line == "<!-- PAGEBREAK -->":
            doc.add_paragraph().add_run().add_break(WD_BREAK.PAGE)
            idx += 1
            continue
        if not line:
            idx += 1
            continue
        if line.startswith("# "):
            add_para(doc, line[2:].strip(), "Title", 15)
        elif line.startswith("## "):
            add_para(doc, line[3:].strip(), "Heading 1", 12)
        elif line.startswith("### "):
            add_para(doc, line[4:].strip(), "Heading 2", 10)
        elif line.startswith("- "):
            add_para(doc, line[2:].strip(), "List Bullet", 8.8)
        elif re.match(r"^\d+\. ", line):
            add_para(doc, re.sub(r"^\d+\. ", "", line), "List Number", 8.8)
        elif line.startswith("|"):
            table_lines = []
            while idx < len(lines) and lines[idx].startswith("|"):
                table_lines.append(lines[idx])
                idx += 1
            rows = []
            for table_line in table_lines:
                cells = [clean(cell) for cell in table_line.strip().strip("|").split("|")]
                if cells and all(re.fullmatch(r":?-{3,}:?", c or "") for c in cells):
                    continue
                rows.append(cells)
            add_table(doc, rows)
            continue
        else:
            add_para(doc, line, None, 9.0)
        idx += 1
    doc.save(path)


def docx_page_breaks(path: Path) -> int:
    with zipfile.ZipFile(path) as zf:
        xml = zf.read("word/document.xml").decode("utf-8", errors="ignore")
    return xml.count('w:type="page"')


def main() -> None:
    summary = load_json(SUMMARY_PATH, {})
    OUT_MD.mkdir(parents=True, exist_ok=True)
    OUT_DOCX.mkdir(parents=True, exist_ok=True)
    verification = {}

    for person, pages in PAGES.items():
        if len(pages) != 30:
            raise AssertionError(f"{person}: expected 30 pages, got {len(pages)}")
        markdown = build_markdown(person, summary[person])
        md_path = OUT_MD / f"{person}_업무규칙_인수인계서_30p_{RUN_DATE}.md"
        docx_path = OUT_DOCX / f"{person}_업무규칙_인수인계서_30p_{RUN_DATE}.docx"
        md_path.write_text(markdown, encoding="utf-8")
        markdown_to_docx(markdown, docx_path)
        breaks = docx_page_breaks(docx_path)
        words = len(re.findall(r"\S+", markdown))
        with zipfile.ZipFile(docx_path) as zf:
            names = set(zf.namelist())
            assert "[Content_Types].xml" in names
            assert "word/document.xml" in names
        verification[person] = {
            "markdown": str(md_path),
            "docx": str(docx_path),
            "sections": len(pages),
            "manual_page_breaks": breaks,
            "estimated_min_pages": breaks + 1,
            "markdown_tokens_by_whitespace": words,
            "docx_bytes": docx_path.stat().st_size,
        }
        print(person, verification[person])

    VERIFY_PATH.write_text(json.dumps(verification, ensure_ascii=False, indent=2), encoding="utf-8")
    print("verification", VERIFY_PATH)


if __name__ == "__main__":
    main()
